Steps.DetectionScript:
$audioSvc = Get-Service -Name AudioSrv -ErrorAction SilentlyContinue
$epSvc    = Get-Service -Name AudioEndpointBuilder -ErrorAction SilentlyContinue
if ((-not $audioSvc) -or (-not $epSvc)) { return @{ Status = 'Failed'; Message = 'Audio services not found' } }
if ($audioSvc.Status -ne 'Running') { return @{ Status = 'Failed'; Message = "AudioSrv is $($audioSvc.Status)" } }
if ($epSvc.Status -ne 'Running')    { return @{ Status = 'Failed'; Message = "AudioEndpointBuilder is $($epSvc.Status)" } }
return @{ Status = 'Passed'; Message = 'AudioSrv and AudioEndpointBuilder are running' }

Add-Type -AssemblyName System.Windows.Forms -ErrorAction SilentlyContinue
try {
    # Use Get-WmiObject as a PS5-compatible approach
    $endpoints = Get-WmiObject -Query "SELECT * FROM Win32_SoundDevice" -ErrorAction Stop
    if (-not $endpoints) { return @{ Status = 'Failed'; Message = 'No sound devices found' } }
    $active = $endpoints | Where-Object { $_.StatusInfo -eq 3 }  # 3 = Enabled
    if ($active) {
        $names = ($active | Select-Object -ExpandProperty Name) -join ', '
        return @{ Status = 'Passed'; Message = "Active device(s): $names" }
    }
    $names = ($endpoints | Select-Object -ExpandProperty Name) -join ', '
    return @{ Status = 'Warning'; Message = "Found but status unknown: $names" }
} catch {
    return @{ Status = 'Warning'; Message = 'Unable to enumerate sound devices' }
}

$audioDevices = Get-WmiObject -Class Win32_PnPEntity -ErrorAction SilentlyContinue |
    Where-Object { $_.Name -match 'audio|sound|speaker|headset|realtek|conexant|IDT|Synaptics.*audio|Intel.*Smart Sound' }
if (-not $audioDevices) { return @{ Status = 'Warning'; Message = 'No audio PnP devices found' } }
$errored = $audioDevices | Where-Object { $_.ConfigManagerErrorCode -ne 0 }
if ($errored) {
    $names = ($errored | Select-Object -ExpandProperty Name) -join ', '
    return @{ Status = 'Failed'; Message = "Driver error on: $names" }
}
$names = ($audioDevices | Select-Object -ExpandProperty Name) -join ', '
return @{ Status = 'Passed'; Message = "Healthy: $names" }

        try {
            Add-Type -TypeDefinition @'
using System.Runtime.InteropServices;
public class AudioUtils {
    [DllImport("winmm.dll")] public static extern int waveOutGetVolume(IntPtr h, out uint vol);
}
'@ -ErrorAction SilentlyContinue
            $vol = 0
            $result = [AudioUtils]::waveOutGetVolume([System.IntPtr]::Zero, [ref]$vol)
            $left  = $vol -band 0xFFFF
            $pct   = [math]::Round($left / 0xFFFF * 100)
            if ($pct -eq 0) { return @{ Status = 'Warning'; Message = 'System volume is at 0%' } }
            return @{ Status = 'Passed'; Message = "Volume at $pct%" }
        } catch {
            return @{ Status = 'Warning'; Message = 'Unable to query volume level' }
        }

$svc = Get-Service -Name bthserv -ErrorAction SilentlyContinue
if (-not $svc) { return @{ Status = 'Warning'; Message = 'Bluetooth service (bthserv) not found — adapter may not be present' } }
if ($svc.Status -ne 'Running') { return @{ Status = 'Failed'; Message = "Bluetooth service is $($svc.Status)" } }
$adapter = Get-WmiObject -Class Win32_PnPEntity -ErrorAction SilentlyContinue |
    Where-Object { $_.Name -match 'Bluetooth' -and $_.ConfigManagerErrorCode -eq 0 }
if ($adapter) { return @{ Status = 'Passed'; Message = 'Bluetooth service running, adapter detected' } }
return @{ Status = 'Warning'; Message = 'Bluetooth service running but no adapter confirmed' }

try {
    $radioKey = 'HKLM:\SYSTEM\CurrentControlSet\Services\BTHPORT\Parameters\Devices'
    if (-not (Test-Path $radioKey)) { return @{ Status = 'Warning'; Message = 'No Bluetooth devices in registry' } }
    $devices = Get-ChildItem $radioKey -ErrorAction SilentlyContinue
    if (-not $devices) { return @{ Status = 'Warning'; Message = 'No paired Bluetooth devices found' } }
    $count = $devices.Count
    return @{ Status = 'Passed'; Message = "$count paired Bluetooth device(s) found" }
} catch {
    return @{ Status = 'Warning'; Message = 'Unable to enumerate Bluetooth devices' }
}

$btAudio = Get-WmiObject -Class Win32_SoundDevice -ErrorAction SilentlyContinue |
    Where-Object { $_.Name -match 'Bluetooth|BT|Headset|Headphones' }
if ($btAudio) {
    $names = ($btAudio | Select-Object -ExpandProperty Name) -join ', '
    return @{ Status = 'Passed'; Message = "BT audio endpoint: $names" }
}
$btAudio2 = Get-WmiObject -Class Win32_PnPEntity -ErrorAction SilentlyContinue |
    Where-Object { $_.Name -match 'Bluetooth.*audio|Hands.Free|A2DP|Headset' }
if ($btAudio2) {
    $names = ($btAudio2 | Select-Object -ExpandProperty Name) -join ', '
    return @{ Status = 'Passed'; Message = "BT audio profile active: $names" }
}
return @{ Status = 'Warning'; Message = 'No Bluetooth audio endpoint detected' }

$micKey = 'HKCU:\SOFTWARE\Microsoft\Windows\CurrentVersion\CapabilityAccessManager\ConsentStore\microphone'
$value = (Get-ItemProperty -Path $micKey -Name Value -ErrorAction SilentlyContinue).Value
if ($value -eq 'Deny') { return @{ Status = 'Failed'; Message = 'Microphone access is denied for this user' } }
$desktopKey = "$micKey\NonPackaged"
$desktopVal = (Get-ItemProperty -Path $desktopKey -Name Value -ErrorAction SilentlyContinue).Value
if ($desktopVal -eq 'Deny') { return @{ Status = 'Failed'; Message = 'Microphone access denied for desktop apps' } }
return @{ Status = 'Passed'; Message = 'Microphone access is allowed' }
